    // Get critical path to prioritize
    const criticalPath = new CriticalPath(graph);
    const criticalPathIds = criticalPath.getCriticalPath();

    // Sort ready tasks by priority (critical path first)
    readyTasks.sort((a, b) => {
      const aOnCritical = criticalPathIds.includes(a.id);
      const bOnCritical = criticalPathIds.includes(b.id);
      if (aOnCritical && !bOnCritical) return -1;
      if (!aOnCritical && bOnCritical) return 1;
      return criticalPath.getPriorityScore(b.id) - criticalPath.getPriorityScore(a.id);
